10	const PROCESSING_FEE = 5;
11	const DEDUCTIBLE = 100;
12	const INITIAL_ASSESSMENT_MULTIPLIER = 1.1;
13	const SUBSEQUENT_CONTRACT_MULTIPLIER = 0.85;
14	const ALIKE_BUNDLE_DISCOUNT = 15;
15	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
19	const HIGH_ENCHANTMENT_CLAIM_FACTOR = 0.5;
20	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
21	const LOYALTY_THRESHOLD = 2;
22	const COMPONENT_TYPES = ["rune", "moonstone"];
23	
24	type Item = { type: string; cursed?: boolean; enchantment?: number };
25	
26	function ceilToWholeGold(amount: number): number {
27	  return Math.ceil(Math.round(amount * 1e6) / 1e6);
28	}
29	
30	function basePremiumFor(itemType: string): number {
31	  return BASE_PREMIUMS[itemType] ?? 0;
32	}
33	
34	function isHighlyEnchanted(item: Item): boolean {
35	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
36	}
37	
38	function itemPremium(item: Item): number {
39	  const base = basePremiumFor(item.type);
40	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE_MULTIPLIER : 1;
41	  const enchantmentMultiplier = isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER : 1;
42	  return base * cursedMultiplier * enchantmentMultiplier;
43	}
44	
45	function countOfType(items: Array<Item>, itemType: string): number {
46	  return items.filter((item) => item.type === itemType).length;
47	}
48	
49	function alikeBundleDiscount(items: Array<Item>): number {
50	  const bundleCount = COMPONENT_TYPES.reduce(
51	    (sum, componentType) => sum + Math.floor(countOfType(items, componentType) / 3),
52	    0,
53	  );
54	  return bundleCount * ALIKE_BUNDLE_DISCOUNT;
55	}
56	
57	function contractHistoryMultiplierFor(previousQuotes: number): number {
58	  return previousQuotes >= 1 ? SUBSEQUENT_CONTRACT_MULTIPLIER : INITIAL_ASSESSMENT_MULTIPLIER;
59	}
60	
61	function loyaltyMultiplierFor(yearsWithMHPCO: number): number {
62	  return yearsWithMHPCO >= LOYALTY_THRESHOLD ? LOYALTY_DISCOUNT_MULTIPLIER : 1;
63	}
64	
65	export function quote(input: { items: Array<Item>; previousQuotes?: number; yearsWithMHPCO?: number }): number {
66	  const itemPremiumSum = input.items.reduce((sum, item) => sum + itemPremium(item), 0);
67	  const itemsTotal = itemPremiumSum - alikeBundleDiscount(input.items);
68	  const contractHistoryMultiplier = contractHistoryMultiplierFor(input.previousQuotes ?? 0);
69	  const loyaltyMultiplier = loyaltyMultiplierFor(input.yearsWithMHPCO ?? 0);
70	  const total = itemsTotal * contractHistoryMultiplier * loyaltyMultiplier + PROCESSING_FEE;
71	  return ceilToWholeGold(total);
72	}
73	
74	function reimbursableAmount(damage: { itemType: string; amount: number }, policyItem: Item | undefined): number {
75	  if (policyItem && (policyItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
76	    return damage.amount * HIGH_ENCHANTMENT_CLAIM_FACTOR;
77	  }
78	  return damage.amount;
79	}
80	
81	export function claim(
82	  incident: { damages: Array<{ itemType: string; amount: number }> },
83	  policy: { items: Array<Item> },
84	): number {
85	  const totalReimbursable = incident.damages.reduce((sum, damage) => {
86	    const policyItem = policy.items.find((item) => item.type === damage.itemType);
87	    return sum + reimbursableAmount(damage, policyItem);
88	  }, 0);
89	  return Math.max(0, totalReimbursable - DEDUCTIBLE);
90	}
